/**
 * Splash Route - Landing page
 *
 * Auto-navigates after 3.6 seconds based on:
 * - Authenticated (mvv exists) → HOME
 * - Has mvv_ts (previously signed out) → SIGN IN
 * - No mvv or mvv_ts → Show buttons (stay on splash)
 */

import PubSub from 'pubsub-js';
import AppBroadcast from '../core/appBroadcast.js';
import { FEATURE_FLAGS } from '../../../../shared/featureFlags.js';

export function render() {
  return `
    <div class="splash-container">
      <div class="splash-content">
        <h1>StreamSyncEngage</h1>
        <p class="tagline">Real-time messaging and account management platform</p>

        <div class="splash-loader" id="splash-loader">
          <div class="spinner"></div>
          <p class="loading-text">Loading...</p>
        </div>

        <div class="splash-actions" id="splash-actions" style="display: none;">
          <button class="btn btn-primary" data-route="signin">
            Sign In
          </button>
          <button class="btn btn-secondary" data-route="signup">
            Sign Up
          </button>
        </div>
      </div>
    </div>

    <style>
      .splash-container {
        display: flex;
        justify-content: center;
        align-items: center;
        min-height: 100vh;
        background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
        padding: 20px;
      }

      .splash-content {
        text-align: center;
        color: white;
        max-width: 500px;
      }

      .splash-content h1 {
        font-size: 3rem;
        margin-bottom: 1rem;
        font-weight: 700;
      }

      .tagline {
        font-size: 1.2rem;
        margin-bottom: 3rem;
        opacity: 0.9;
      }

      .splash-loader {
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: 1.5rem;
      }

      .spinner {
        width: 50px;
        height: 50px;
        border: 4px solid rgba(255, 255, 255, 0.3);
        border-top-color: white;
        border-radius: 50%;
        animation: spin 1s linear infinite;
      }

      @keyframes spin {
        to { transform: rotate(360deg); }
      }

      .loading-text {
        font-size: 1rem;
        opacity: 0.8;
        animation: pulse 2s ease-in-out infinite;
      }

      @keyframes pulse {
        0%, 100% { opacity: 0.6; }
        50% { opacity: 1; }
      }

      .splash-actions {
        display: flex;
        gap: 1rem;
        justify-content: center;
        margin-top: 2rem;
      }

      .btn {
        padding: 12px 24px;
        border: none;
        border-radius: 6px;
        font-size: 1rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.3s ease;
      }

      .btn-primary {
        background: white;
        color: #667eea;
      }

      .btn-primary:hover {
        transform: translateY(-2px);
        box-shadow: 0 4px 12px rgba(255, 255, 255, 0.3);
      }

      .btn-secondary {
        background: rgba(255, 255, 255, 0.2);
        color: white;
        border: 2px solid white;
      }

      .btn-secondary:hover {
        background: rgba(255, 255, 255, 0.3);
        transform: translateY(-2px);
      }
    </style>
  `;
}

export function init() {
  console.log('[SplashRoute] Initialized - checking authentication state in 3.6 seconds...');

  // Check authentication after 3.6 seconds
  setTimeout(() => {
    const mvvToken = localStorage.getItem(FEATURE_FLAGS.FF_SSE_LS_TOKEN);
    const mvvTs = localStorage.getItem('mvv_ts');

    console.log('[SplashRoute] localStorage check:', {
      hasMvvToken: !!mvvToken,
      hasMvvTs: !!mvvTs
    });

    const loader = document.getElementById('splash-loader');
    const actions = document.getElementById('splash-actions');

    if (mvvToken) {
      // User has auth token → navigate to HOME
      console.log('[SplashRoute] Auth token found → HOME');
      PubSub.publish(AppBroadcast.ROUTE_NAV, { route: 'home' });
    } else if (mvvTs) {
      // Has mvv_ts (previously signed out) → navigate to SIGN IN
      console.log('[SplashRoute] Previous session detected (mvv_ts exists) → SIGN IN');
      PubSub.publish(AppBroadcast.ROUTE_NAV, { route: 'signin' });
    } else {
      // No mvv or mvv_ts → Show buttons and stay on splash
      console.log('[SplashRoute] New user (no session history) → Showing buttons');
      if (loader) loader.style.display = 'none';
      if (actions) actions.style.display = 'flex';

      // Attach button click handlers to publish ROUTE_NAV
      const buttons = document.querySelectorAll('[data-route]');
      buttons.forEach(btn => {
        btn.addEventListener('click', () => {
          const route = btn.getAttribute('data-route');
          console.log(`[SplashRoute] Button clicked - navigating to: ${route}`);
          PubSub.publish(AppBroadcast.ROUTE_NAV, { route });
        });
      });
    }
  }, 3600); // 3.6 seconds
}
